  1вҶ’import { createKeyv } from '@keyv/redis';
  2вҶ’import { Global, Module } from '@nestjs/common';
  3вҶ’import { Redis } from 'ioredis';
  4вҶ’
  5вҶ’import {
  6вҶ’	CACHE_READ_MANAGER,
  7вҶ’	CACHE_WRITE_MANAGER,
  8вҶ’	REDIS_READ_CLIENT,
  9вҶ’	REDIS_WRITE_CLIENT,
 10вҶ’} from '@modules/cache/cache.constant';
 11вҶ’import { CacheService } from '@modules/cache/cache.service';
 12вҶ’
 13вҶ’import {
 14вҶ’	NODE_ENV,
 15вҶ’	REDIS_READ_URL,
 16вҶ’	REDIS_URL,
 17вҶ’	SERVER_NAME,
 18вҶ’} from '@constants/env-variables.constant';
 19вҶ’
 20вҶ’import { getEnv } from '@utils/get-env-variable.util';
 21вҶ’
 22вҶ’@Global()
 23вҶ’@Module({
 24вҶ’	providers: [
 25вҶ’		CacheService,
 26вҶ’		{
 27вҶ’			provide: CACHE_WRITE_MANAGER,
 28вҶ’			// eslint-disable-next-line custom-rules/require-object-params
 29вҶ’			useFactory: () => {
 30вҶ’				const namespace = `${getEnv<string>({ key: SERVER_NAME })}:${getEnv<string>({ key: NODE_ENV })}`;
 31вҶ’				const cacheWriteUrl = getEnv<string>({ key: REDIS_URL });
 32вҶ’				return createKeyv(cacheWriteUrl, {
 33вҶ’					namespace,
 34вҶ’					useUnlink: true,
 35вҶ’					keyPrefixSeparator: ':',
 36вҶ’				});
 37вҶ’			},
 38вҶ’		},
 39вҶ’		{
 40вҶ’			provide: CACHE_READ_MANAGER,
 41вҶ’			// eslint-disable-next-line custom-rules/require-object-params
 42вҶ’			useFactory: () => {
 43вҶ’				const namespace = `${getEnv<string>({ key: SERVER_NAME })}:${getEnv<string>({ key: NODE_ENV })}`;
 44вҶ’				const cacheReadUrl = getEnv<string>({ key: REDIS_READ_URL });
 45вҶ’				return createKeyv(cacheReadUrl, {
 46вҶ’					namespace,
 47вҶ’					useUnlink: true,
 48вҶ’					keyPrefixSeparator: ':',
 49вҶ’				});
 50вҶ’			},
 51вҶ’		},
 52вҶ’		{
 53вҶ’			provide: REDIS_WRITE_CLIENT,
 54вҶ’			// eslint-disable-next-line custom-rules/require-object-params
 55вҶ’			useFactory: () => {
 56вҶ’				const cacheUrl = getEnv<string>({ key: REDIS_URL });
 57вҶ’				return new Redis(cacheUrl, {
 58вҶ’					// eslint-disable-next-line custom-rules/require-object-params
 59вҶ’					retryStrategy: (times) => {
 60вҶ’						return Math.min(times * 50, 2000);
 61вҶ’					},
 62вҶ’					maxRetriesPerRequest: 3,
 63вҶ’					enableReadyCheck: true,
 64вҶ’					connectTimeout: 10000,
 65вҶ’					lazyConnect: false,
 66вҶ’					// eslint-disable-next-line custom-rules/require-object-params
 67вҶ’					reconnectOnError: (err) => {
 68вҶ’						const targetError = 'READONLY';
 69вҶ’						return err.message.includes(targetError);
 70вҶ’					},
 71вҶ’				});
 72вҶ’			},
 73вҶ’		},
 74вҶ’		{
 75вҶ’			provide: REDIS_READ_CLIENT,
 76вҶ’			// eslint-disable-next-line custom-rules/require-object-params
 77вҶ’			useFactory: () => {
 78вҶ’				const cacheReadUrl = getEnv<string>({ key: REDIS_READ_URL });
 79вҶ’				return new Redis(cacheReadUrl, {
 80вҶ’					// eslint-disable-next-line custom-rules/require-object-params
 81вҶ’					retryStrategy: (times) => {
 82вҶ’						return Math.min(times * 50, 2000);
 83вҶ’					},
 84вҶ’					maxRetriesPerRequest: 3,
 85вҶ’					enableReadyCheck: true,
 86вҶ’					connectTimeout: 10000,
 87вҶ’					lazyConnect: false,
 88вҶ’					readOnly: true,
 89вҶ’				});
 90вҶ’			},
 91вҶ’		},
 92вҶ’	],
 93вҶ’	exports: [
 94вҶ’		CacheService,
 95вҶ’		REDIS_WRITE_CLIENT,
 96вҶ’		REDIS_READ_CLIENT,
 97вҶ’		CACHE_WRITE_MANAGER,
 98вҶ’		CACHE_READ_MANAGER,
 99вҶ’	],
100вҶ’})
101вҶ’export class CacheModule {}
102вҶ’

1вҶ’export const REDIS_READ_CLIENT = 'REDIS_READ_CLIENT';
2вҶ’export const REDIS_WRITE_CLIENT = 'REDIS_WRITE_CLIENT';
3вҶ’export const CACHE_WRITE_MANAGER = 'CACHE_WRITE_MANAGER';
4вҶ’export const CACHE_READ_MANAGER = 'CACHE_READ_MANAGER';
