  1вҶ’import { Logger } from '@nestjs/common';
  2вҶ’import { Test, TestingModule } from '@nestjs/testing';
  3вҶ’import { Lock } from 'redlock';
  4вҶ’
  5вҶ’import {
  6вҶ’	CACHE_READ_MANAGER,
  7вҶ’	CACHE_WRITE_MANAGER,
  8вҶ’	REDIS_READ_CLIENT,
  9вҶ’	REDIS_WRITE_CLIENT,
 10вҶ’} from '@modules/cache/cache.constant';
 11вҶ’import { CacheService } from '@modules/cache/cache.service';
 12вҶ’import { ConsistencyLevel, Namespaces } from '@modules/cache/types/cache.interface';
 13вҶ’
 14вҶ’const mockCacheWriteManager = {
 15вҶ’	get: jest.fn(),
 16вҶ’	set: jest.fn(),
 17вҶ’	delete: jest.fn(),
 18вҶ’	clear: jest.fn(),
 19вҶ’};
 20вҶ’
 21вҶ’const mockCacheReadManager = {
 22вҶ’	get: jest.fn(),
 23вҶ’	set: jest.fn(),
 24вҶ’	delete: jest.fn(),
 25вҶ’	clear: jest.fn(),
 26вҶ’};
 27вҶ’
 28вҶ’const mockRedisWriteClient = {
 29вҶ’	incr: jest.fn(),
 30вҶ’	on: jest.fn(),
 31вҶ’};
 32вҶ’
 33вҶ’const mockRedisReadClient = {
 34вҶ’	on: jest.fn(),
 35вҶ’};
 36вҶ’
 37вҶ’const mockLock = {
 38вҶ’	resources: ['test-lock'],
 39вҶ’	release: jest.fn(),
 40вҶ’};
 41вҶ’
 42вҶ’const mockRedlock = {
 43вҶ’	acquire: jest.fn().mockResolvedValue(mockLock),
 44вҶ’};
 45вҶ’
 46вҶ’jest.mock('redlock', () => {
 47вҶ’	return {
 48вҶ’		__esModule: true,
 49вҶ’		default: jest.fn().mockImplementation(() => mockRedlock),
 50вҶ’	};
