 53вҶ’describe('CacheService', () => {
 54вҶ’	let service: CacheService;
 55вҶ’
 56вҶ’	beforeEach(async () => {
 57вҶ’		const module: TestingModule = await Test.createTestingModule({
 58вҶ’			providers: [
 59вҶ’				CacheService,
 60вҶ’				{ provide: CACHE_WRITE_MANAGER, useValue: mockCacheWriteManager },
 61вҶ’				{ provide: CACHE_READ_MANAGER, useValue: mockCacheReadManager },
 62вҶ’				{ provide: REDIS_WRITE_CLIENT, useValue: mockRedisWriteClient },
 63вҶ’				{ provide: REDIS_READ_CLIENT, useValue: mockRedisReadClient },
 64вҶ’			],
 65вҶ’		}).compile();
 66вҶ’
 67вҶ’		service = module.get<CacheService>(CacheService);
 68вҶ’
 69вҶ’		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
 70вҶ’		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
 71вҶ’		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
 72вҶ’	});
 73вҶ’
 74вҶ’	afterEach(() => jest.clearAllMocks());
 75вҶ’
 76вҶ’	describe('get', () => {
 77вҶ’		it('should read from replica with EVENTUAL consistency', async () => {
 78вҶ’			const testValue = { data: 'test' };
 79вҶ’			mockCacheReadManager.get.mockResolvedValue(testValue);
 80вҶ’
 81вҶ’			const result = await service.get({
 82вҶ’				namespace: Namespaces.SESSION,
 83вҶ’				key: 'test-key',
 84вҶ’				consistencyLevel: ConsistencyLevel.EVENTUAL,
 85вҶ’			});
 86вҶ’
 87вҶ’			expect(mockCacheReadManager.get).toHaveBeenCalledWith('session:test-key');
 88вҶ’			expect(mockCacheWriteManager.get).not.toHaveBeenCalled();
 89вҶ’			expect(result).toEqual(testValue);
 90вҶ’		});
 91вҶ’
 92вҶ’		it('should read from master with STRONG consistency', async () => {
 93вҶ’			const testValue = { data: 'test' };
 94вҶ’			mockCacheWriteManager.get.mockResolvedValue(testValue);
 95вҶ’
 96вҶ’			const result = await service.get({
 97вҶ’				namespace: Namespaces.SESSION,
 98вҶ’				key: 'test-key',
 99вҶ’				consistencyLevel: ConsistencyLevel.STRONG,
100вҶ’			});
101вҶ’
102вҶ’			expect(mockCacheWriteManager.get).toHaveBeenCalledWith('session:test-key');
103вҶ’			expect(mockCacheReadManager.get).not.toHaveBeenCalled();
104вҶ’			expect(result).toEqual(testValue);
105вҶ’		});
106вҶ’
107вҶ’		it('should fall back to master when replica is unhealthy', async () => {
108вҶ’			const testValue = { data: 'test' };
109вҶ’			mockCacheReadManager.get.mockRejectedValueOnce(new Error('connection failed'));
110вҶ’			mockCacheWriteManager.get.mockResolvedValue(testValue);
111вҶ’
112вҶ’			const result = await service.get({
113вҶ’				namespace: Namespaces.SESSION,
114вҶ’				key: 'test-key',
115вҶ’				consistencyLevel: ConsistencyLevel.EVENTUAL,
116вҶ’			});
117вҶ’
118вҶ’			expect(mockCacheReadManager.get).toHaveBeenCalled();
119вҶ’			expect(mockCacheWriteManager.get).toHaveBeenCalled();
120вҶ’			expect(result).toEqual(testValue);
121вҶ’		});
122вҶ’
123вҶ’		it('should read from master when key was recently written', async () => {
124вҶ’			const testValue = { data: 'test' };
125вҶ’			mockCacheWriteManager.get.mockResolvedValue(testValue);
126вҶ’			mockCacheWriteManager.set.mockResolvedValue(undefined);
127вҶ’
128вҶ’			await service.set({
129вҶ’				namespace: Namespaces.SESSION,
130вҶ’				key: 'test-key',
131вҶ’				value: testValue,
132вҶ’			});
133вҶ’
134вҶ’			jest.clearAllMocks();
135вҶ’			mockCacheWriteManager.get.mockResolvedValue(testValue);
136вҶ’
137вҶ’			const result = await service.get({
138вҶ’				namespace: Namespaces.SESSION,
139вҶ’				key: 'test-key',
140вҶ’				consistencyLevel: ConsistencyLevel.EVENTUAL,
141вҶ’			});
142вҶ’
143вҶ’			expect(mockCacheWriteManager.get).toHaveBeenCalledWith('session:test-key');
144вҶ’			expect(mockCacheReadManager.get).not.toHaveBeenCalled();
145вҶ’			expect(result).toEqual(testValue);
146вҶ’		});
147вҶ’
148вҶ’		it('should return null on cache miss', async () => {
149вҶ’			mockCacheReadManager.get.mockResolvedValue(undefined);
150вҶ’
151вҶ’			const result = await service.get({
152вҶ’				namespace: Namespaces.SESSION,
153вҶ’				key: 'missing-key',
154вҶ’			});
155вҶ’
156вҶ’			expect(result).toBeNull();
157вҶ’		});
158вҶ’	});
159вҶ’
160вҶ’	describe('set', () => {
161вҶ’		it('should write to master and track recent write', async () => {
162вҶ’			mockCacheWriteManager.set.mockResolvedValue(undefined);
163вҶ’
164вҶ’			await service.set({
165вҶ’				namespace: Namespaces.AUTH_CODE,
166вҶ’				key: 'my-key',
167вҶ’				value: 'my-value',
168вҶ’				ttl: 3000,
169вҶ’			});
170вҶ’
171вҶ’			expect(mockCacheWriteManager.set).toHaveBeenCalledWith(
172вҶ’				'auth-code:my-key',
173вҶ’				'my-value',
174вҶ’				3000,
175вҶ’			);
176вҶ’		});
177вҶ’
178вҶ’		it('should throw CacheError when set fails', async () => {
179вҶ’			mockCacheWriteManager.set.mockRejectedValue(new Error('write failure'));
180вҶ’
181вҶ’			await expect(
182вҶ’				service.set({ namespace: Namespaces.SESSION, key: 'k', value: 'v' }),
183вҶ’			).rejects.toMatchObject({ code: 'OPERATION_FAILED' });
184вҶ’		});
185вҶ’	});
186вҶ’
187вҶ’	describe('deleteOne', () => {
188вҶ’		it('should remove key from write manager and return true', async () => {
189вҶ’			mockCacheWriteManager.delete.mockResolvedValue(true);
190вҶ’
191вҶ’			const result = await service.deleteOne({
192вҶ’				namespace: Namespaces.SESSION,
193вҶ’				key: 'delete-me',
194вҶ’			});
195вҶ’
196вҶ’			expect(mockCacheWriteManager.delete).toHaveBeenCalledWith('session:delete-me');
197вҶ’			expect(result).toBe(true);
198вҶ’		});
199вҶ’
200вҶ’		it('should return false when delete fails', async () => {
201вҶ’			mockCacheWriteManager.delete.mockRejectedValue(new Error('delete error'));
202вҶ’
203вҶ’			const result = await service.deleteOne({
204вҶ’				namespace: Namespaces.SESSION,
205вҶ’				key: 'fail-key',
206вҶ’			});
207вҶ’
208вҶ’			expect(result).toBe(false);
209вҶ’		});
210вҶ’	});
211вҶ’
212вҶ’	describe('deleteAll', () => {
213вҶ’		it('should clear both managers and return true', async () => {
214вҶ’			mockCacheWriteManager.clear.mockResolvedValue(undefined);
215вҶ’			mockCacheReadManager.clear.mockResolvedValue(undefined);
216вҶ’
217вҶ’			const result = await service.deleteAll({ namespace: Namespaces.SESSION });
218вҶ’
219вҶ’			expect(mockCacheWriteManager.clear).toHaveBeenCalled();
220вҶ’			expect(mockCacheReadManager.clear).toHaveBeenCalled();
221вҶ’			expect(result).toBe(true);
222вҶ’		});
223вҶ’	});
224вҶ’
225вҶ’	describe('incrementByOne', () => {
226вҶ’		it('should call INCR on write client', async () => {
227вҶ’			mockRedisWriteClient.incr.mockResolvedValue(1);
228вҶ’
229вҶ’			await service.incrementByOne({ namespace: Namespaces.SESSION, key: 'counter' });
230вҶ’
231вҶ’			expect(mockRedisWriteClient.incr).toHaveBeenCalledWith('session:counter');
232вҶ’		});
233вҶ’
234вҶ’		it('should throw when INCR fails', async () => {
235вҶ’			mockRedisWriteClient.incr.mockRejectedValue(new Error('incr error'));
236вҶ’
237вҶ’			await expect(
238вҶ’				service.incrementByOne({ namespace: Namespaces.SESSION, key: 'counter' }),
239вҶ’			).rejects.toThrow('incr error');
240вҶ’		});
241вҶ’	});
242вҶ’
243вҶ’	describe('withLock', () => {
244вҶ’		it('should acquire and release lock around operation', async () => {
245вҶ’			const operationResult = 'result';
246вҶ’			const operation = jest.fn().mockResolvedValue(operationResult);
247вҶ’
248вҶ’			const result = await service.withLock({
249вҶ’				lockKey: 'my-lock',
250вҶ’				operation,
251вҶ’				ttl: 3000,
252вҶ’			});
253вҶ’
254вҶ’			expect(mockRedlock.acquire).toHaveBeenCalledWith(['my-lock'], 3000);
255вҶ’			expect(operation).toHaveBeenCalled();
256вҶ’			expect(mockLock.release).toHaveBeenCalled();
257вҶ’			expect(result).toBe(operationResult);
258вҶ’		});
259вҶ’
260вҶ’		it('should release lock even when operation throws', async () => {
261вҶ’			const operation = jest.fn().mockRejectedValue(new Error('operation failed'));
262вҶ’
263вҶ’			await expect(
264вҶ’				service.withLock({ lockKey: 'error-lock', operation }),
265вҶ’			).rejects.toThrow('operation failed');
266вҶ’
267вҶ’			expect(mockLock.release).toHaveBeenCalled();
268вҶ’		});
269вҶ’	});
270вҶ’
271вҶ’	describe('acquireLock', () => {
272вҶ’		it('should return a Lock object', async () => {
273вҶ’			const lock = await service.acquireLock({ lockKey: 'acquire-lock', ttl: 5000 });
274вҶ’
275вҶ’			expect(mockRedlock.acquire).toHaveBeenCalledWith(['acquire-lock'], 5000);
276вҶ’			expect(lock).toBe(mockLock);
277вҶ’		});
278вҶ’	});
279вҶ’
280вҶ’	describe('releaseLock', () => {
281вҶ’		it('should call release on the provided lock', async () => {
282вҶ’			await service.releaseLock({ lock: mockLock as unknown as Lock });
283вҶ’
284вҶ’			expect(mockLock.release).toHaveBeenCalled();
285вҶ’		});
286вҶ’	});
287вҶ’
288вҶ’	describe('has', () => {
289вҶ’		it('should return true when key exists', async () => {
290вҶ’			mockCacheReadManager.get.mockResolvedValue({ data: 'value' });
291вҶ’
292вҶ’			const result = await service.has({ namespace: Namespaces.SESSION, key: 'exists' });
293вҶ’
294вҶ’			expect(result).toBe(true);
295вҶ’		});
296вҶ’
297вҶ’		it('should return false when key does not exist', async () => {
298вҶ’			mockCacheReadManager.get.mockResolvedValue(undefined);
299вҶ’
300вҶ’			const result = await service.has({
301вҶ’				namespace: Namespaces.SESSION,
302вҶ’				key: 'missing',
303вҶ’			});
304вҶ’
305вҶ’			expect(result).toBe(false);
306вҶ’		});
307вҶ’	});
308вҶ’});
