  1вҶ’import { Inject, Injectable, Logger } from '@nestjs/common';
  2вҶ’import { Redis } from 'ioredis';
  3вҶ’import Keyv from 'keyv';
  4вҶ’import Redlock, { Lock } from 'redlock';
  5вҶ’
  6вҶ’import {
  7вҶ’	CACHE_READ_MANAGER,
  8вҶ’	CACHE_WRITE_MANAGER,
  9вҶ’	REDIS_READ_CLIENT,
 10вҶ’	REDIS_WRITE_CLIENT,
 11вҶ’} from '@modules/cache/cache.constant';
 12вҶ’import {
 13вҶ’	CacheError,
 14вҶ’	ConsistencyLevel,
 15вҶ’	Namespaces,
 16вҶ’} from '@modules/cache/types/cache.interface';
 17вҶ’
 18вҶ’export { ConsistencyLevel, CacheError } from '@modules/cache/types/cache.interface';
 19вҶ’
 20вҶ’@Injectable()
 21вҶ’export class CacheService {
 22вҶ’	private readonly logger = new Logger(CacheService.name);
 23вҶ’	private readonly redlock: Redlock;
 24вҶ’	private readonly redisWriteClient: Redis;
 25вҶ’	private readonly redisReadClient: Redis;
 26вҶ’	private readonly cacheWriteManager: Keyv;
 27вҶ’	private readonly cacheReadManager: Keyv;
 28вҶ’	private readonly recentWrites = new Map<string, number>();
 29вҶ’	private readonly CONSISTENCY_WINDOW_MS = 1000;
 30вҶ’	private isReadReplicaHealthy = true;
 31вҶ’
 32вҶ’	constructor(
 33вҶ’		@Inject(CACHE_WRITE_MANAGER) cacheWriteManager: Keyv,
 34вҶ’		@Inject(CACHE_READ_MANAGER) cacheReadManager: Keyv,
 35вҶ’		@Inject(REDIS_WRITE_CLIENT) redisWriteClient: Redis,
 36вҶ’		@Inject(REDIS_READ_CLIENT) redisReadClient: Redis,
 37вҶ’	) {
 38вҶ’		this.cacheWriteManager = cacheWriteManager;
 39вҶ’		this.cacheReadManager = cacheReadManager;
 40вҶ’		this.redisWriteClient = redisWriteClient;
 41вҶ’		this.redisReadClient = redisReadClient;
 42вҶ’		this.redlock = new Redlock([redisWriteClient], {
 43вҶ’			driftFactor: 0.01,
 44вҶ’			retryCount: 10,
 45вҶ’			retryDelay: 200,
 46вҶ’			retryJitter: 200,
 47вҶ’		});
 48вҶ’
 49вҶ’		this.setupHealthChecks();
 50вҶ’		this.startRecentWritesCleanup();
 51вҶ’	}
 52вҶ’
 53вҶ’	async get<T>({
 54вҶ’		namespace,
 55вҶ’		key,
 56вҶ’		consistencyLevel = ConsistencyLevel.EVENTUAL,
 57вҶ’	}: {
 58вҶ’		namespace: Namespaces;
 59вҶ’		key: string;
 60вҶ’		consistencyLevel?: ConsistencyLevel;
 61вҶ’	}): Promise<T | null> {
 62вҶ’		const namespacedKey = this.getNamespacedKey({ namespace, key });
 63вҶ’
 64вҶ’		const readFromMaster = this.shouldReadFromMaster({
 65вҶ’			namespace,
 66вҶ’			key: namespacedKey,
 67вҶ’			consistencyLevel,
 68вҶ’		});
 69вҶ’		const cacheManager = readFromMaster ? this.cacheWriteManager : this.cacheReadManager;
 70вҶ’		const source = readFromMaster ? 'master' : 'replica';
 71вҶ’
 72вҶ’		try {
 73вҶ’			const result = (await cacheManager.get(namespacedKey)) as T;
 74вҶ’
 75вҶ’			if (!result) {
 76вҶ’				this.logger.log('Cache miss', { namespace, key, consistencyLevel, source });
 77вҶ’				return null;
 78вҶ’			}
 79вҶ’
 80вҶ’			this.logger.log('Cache hit', { namespace, key });
 81вҶ’
 82вҶ’			return result;
 83вҶ’		} catch (error) {
 84вҶ’			const e = error as Error;
 85вҶ’			this.logger.error(`Error retrieving from cache: ${e.message}`, e.stack, { source });
 86вҶ’
 87вҶ’			if (!readFromMaster && this.isReadReplicaHealthy) {
 88вҶ’				this.logger.warn('Read replica failed, falling back to master', {
 89вҶ’					namespace,
 90вҶ’					key,
 91вҶ’				});
 92вҶ’				this.isReadReplicaHealthy = false;
 93вҶ’				return this.get({ namespace, key, consistencyLevel: ConsistencyLevel.STRONG });
 94вҶ’			}
 95вҶ’
 96вҶ’			throw this.createCacheError({ code: 'CONNECTION_FAILED', originalError: e });
 97вҶ’		}
 98вҶ’	}
 99вҶ’
100вҶ’	async set({
101вҶ’		namespace,
102вҶ’		key,
103вҶ’		value,
104вҶ’		ttl,
