export interface ISession {
	user_id: string;
	session_id: string;
	role: 'admin' | 'member' | null;
	company_id: string | null;
	provider: 'github' | 'google';
	ip: string;
	user_agent: string;
	created_at: string;
	last_active: string;
}

export interface IRefreshToken {
	user_id: string;
	session_id: string;
}

import { randomUUID } from 'crypto';

import { Inject, Injectable, Logger } from '@nestjs/common';
import { Redis } from 'ioredis';

import {
	REDIS_READ_CLIENT,
	REDIS_WRITE_CLIENT,
} from '@modules/cache/cache.constant';
import { IRefreshToken, ISession } from '@modules/session/types/session.interface';

@Injectable()
export class SessionService {
	private readonly logger = new Logger(SessionService.name);
	private readonly SESSION_TTL = 30 * 24 * 60 * 60;

	constructor(
		@Inject(REDIS_WRITE_CLIENT) private readonly redisWrite: Redis,
		@Inject(REDIS_READ_CLIENT) private readonly redisRead: Redis,
	) {}

	async createSession({
		session,
		refreshToken,
	}: {
		session: ISession;
		refreshToken: string;
	}): Promise<void> {
		this.logger.log('Creating session', {
			userId: session.user_id,
			sessionId: session.session_id,
		});

		const sessionKey = `session:${session.user_id}:${session.session_id}`;
		const sessionSetKey = `sessions:${session.user_id}`;
		const refreshKey = `refresh:${refreshToken}`;

		const payload: IRefreshToken = {
			user_id: session.user_id,
			session_id: session.session_id,
		};

		await this.redisWrite
			.multi()
			.set(sessionKey, JSON.stringify(session), 'EX', this.SESSION_TTL)
			.sadd(sessionSetKey, session.session_id)
			.set(refreshKey, JSON.stringify(payload), 'EX', this.SESSION_TTL)
			.exec();
	}

	async getSession({
		userId,
		sessionId,
	}: {
		userId: string;
		sessionId: string;
	}): Promise<ISession | null> {
		this.logger.log('Getting session', { userId, sessionId });

		const sessionKey = `session:${userId}:${sessionId}`;

		let raw: string | null = null;

		try {
			raw = await this.redisRead.get(sessionKey);
		} catch (error) {
			this.logger.warn('Read replica failed, falling back to write client', {
				userId,
				sessionId,
			});
			raw = await this.redisWrite.get(sessionKey);
		}

		if (!raw) {
			return null;
		}

		return JSON.parse(raw) as ISession;
	}

	async updateLastActive({
		userId,
		sessionId,
	}: {
		userId: string;
		sessionId: string;
	}): Promise<void> {
		this.logger.log('Updating last active', { userId, sessionId });

		const sessionKey = `session:${userId}:${sessionId}`;
		const session = await this.getSession({ userId, sessionId });

		if (!session) {
			return;
		}

		session.last_active = new Date().toISOString();
		await this.redisWrite.set(sessionKey, JSON.stringify(session), 'EX', this.SESSION_TTL);
	}

	async destroySession({
		userId,
		sessionId,
		refreshToken,
	}: {
		userId: string;
		sessionId: string;
		refreshToken?: string;
	}): Promise<void> {
		this.logger.log('Destroying session', { userId, sessionId });

		const sessionKey = `session:${userId}:${sessionId}`;
		const sessionSetKey = `sessions:${userId}`;

		const multi = this.redisWrite.multi().del(sessionKey).srem(sessionSetKey, sessionId);

		if (refreshToken) {
			multi.del(`refresh:${refreshToken}`);
		}

		await multi.exec();
	}

	async destroyAllSessions({ userId }: { userId: string }): Promise<void> {
		this.logger.log('Destroying all sessions', { userId });

		const sessionSetKey = `sessions:${userId}`;
		let sessionIds: string[] = [];

		try {
			sessionIds = await this.redisRead.smembers(sessionSetKey);
		} catch (error) {
			this.logger.warn('Read replica failed for smembers, falling back to write client', {
				userId,
			});
			sessionIds = await this.redisWrite.smembers(sessionSetKey);
		}

		if (sessionIds.length === 0) {
			return;
		}

		const multi = this.redisWrite.multi();

		for (const sessionId of sessionIds) {
			multi.del(`session:${userId}:${sessionId}`);
		}

		multi.del(sessionSetKey);

		await multi.exec();
	}

	async destroySessionsByCompanyId({
		userId,
		companyId,
	}: {
		userId: string;
		companyId: string;
	}): Promise<void> {
		this.logger.log('Destroying sessions by company id', { userId, companyId });

		const sessionSetKey = `sessions:${userId}`;
		let sessionIds: string[] = [];

		try {
			sessionIds = await this.redisRead.smembers(sessionSetKey);
		} catch (error) {
			this.logger.warn(
				'Read replica failed for smembers, falling back to write client',
				{ userId },
			);
			sessionIds = await this.redisWrite.smembers(sessionSetKey);
		}

		const sessions = await Promise.all(
			sessionIds.map((sessionId) => this.getSession({ userId, sessionId })),
		);

		const matchingSessions = sessions.filter(
			(session): session is ISession =>
				session !== null && session.company_id === companyId,
		);

		for (const session of matchingSessions) {
			await this.destroySession({
				userId,
				sessionId: session.session_id,
			});
		}
	}

	async validateRefreshToken({
		refreshToken,
	}: {
		refreshToken: string;
	}): Promise<IRefreshToken | null> {
		this.logger.log('Validating refresh token');

		const refreshKey = `refresh:${refreshToken}`;
		let raw: string | null = null;

		try {
			raw = await this.redisRead.get(refreshKey);
		} catch (error) {
			this.logger.warn('Read replica failed, falling back to write client');
			raw = await this.redisWrite.get(refreshKey);
		}

		if (!raw) {
			return null;
		}

		return JSON.parse(raw) as IRefreshToken;
	}

	async rotateRefreshToken({
		oldToken,
		session,
	}: {
		oldToken: string;
		session: ISession;
	}): Promise<string> {
		this.logger.log('Rotating refresh token', {
			userId: session.user_id,
			sessionId: session.session_id,
		});

		const tombstoneKey = `refresh_tombstone:${oldToken}`;
		const oldRefreshKey = `refresh:${oldToken}`;
		const newToken = randomUUID();
		const newRefreshKey = `refresh:${newToken}`;

		const payload: IRefreshToken = {
			user_id: session.user_id,
			session_id: session.session_id,
		};

		await this.redisWrite
			.multi()
			.del(oldRefreshKey)
			.set(tombstoneKey, JSON.stringify(payload), 'EX', 3600)
			.set(newRefreshKey, JSON.stringify(payload), 'EX', this.SESSION_TTL)
			.exec();

		return newToken;
	}

	async detectRefreshTokenReuse({
		refreshToken,
	}: {
		refreshToken: string;
	}): Promise<IRefreshToken | null> {
		this.logger.log('Detecting refresh token reuse');

		const tombstoneKey = `refresh_tombstone:${refreshToken}`;
		let raw: string | null = null;

		try {
			raw = await this.redisRead.get(tombstoneKey);
		} catch (error) {
			this.logger.warn('Read replica failed, falling back to write client');
			raw = await this.redisWrite.get(tombstoneKey);
		}

		if (!raw) {
			return null;
		}

		return JSON.parse(raw) as IRefreshToken;
	}

	async updateCompanyContext({
		userId,
		sessionId,
		companyId,
		role,
	}: {
		userId: string;
		sessionId: string;
		companyId: string | null;
		role: 'admin' | 'member' | null;
	}): Promise<void> {
		this.logger.log('Updating company context', { userId, sessionId, companyId, role });

		const sessionKey = `session:${userId}:${sessionId}`;
		const session = await this.getSession({ userId, sessionId });

		if (!session) {
			return;
		}

		session.company_id = companyId;
		session.role = role;

		await this.redisWrite.set(sessionKey, JSON.stringify(session), 'EX', this.SESSION_TTL);
	}
}

import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import {
	REDIS_READ_CLIENT,
	REDIS_WRITE_CLIENT,
