import { SessionService } from '@modules/session/session.service';
import { ISession } from '@modules/session/types/session.interface';

const mockMulti = {
	set: jest.fn().mockReturnThis(),
	del: jest.fn().mockReturnThis(),
	sadd: jest.fn().mockReturnThis(),
	srem: jest.fn().mockReturnThis(),
	exec: jest.fn().mockResolvedValue([]),
};

const mockRedisWrite = {
	multi: jest.fn().mockReturnValue(mockMulti),
	set: jest.fn(),
	get: jest.fn(),
	del: jest.fn(),
	smembers: jest.fn(),
};

const mockRedisRead = {
	get: jest.fn(),
	smembers: jest.fn(),
};

const mockSession: ISession = {
	user_id: 'user-123',
	session_id: 'session-456',
	role: null,
	company_id: null,
	provider: 'github',
	ip: '127.0.0.1',
	user_agent: 'Mozilla/5.0',
	created_at: '2026-03-22T00:00:00.000Z',
	last_active: '2026-03-22T00:00:00.000Z',
};

jest.mock('crypto', () => ({
	...jest.requireActual('crypto'),
	randomUUID: jest.fn().mockReturnValue('new-token-uuid'),
}));

describe('SessionService', () => {
	let service: SessionService;

	beforeEach(async () => {
		jest.clearAllMocks();

		mockRedisWrite.multi.mockReturnValue(mockMulti);
		mockMulti.set.mockReturnThis();
		mockMulti.del.mockReturnThis();
		mockMulti.sadd.mockReturnThis();
		mockMulti.srem.mockReturnThis();
		mockMulti.exec.mockResolvedValue([]);

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				SessionService,
				{ provide: REDIS_WRITE_CLIENT, useValue: mockRedisWrite },
				{ provide: REDIS_READ_CLIENT, useValue: mockRedisRead },
			],
		}).compile();

		service = module.get<SessionService>(SessionService);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(service).toBeDefined();
	});

	describe('createSession', () => {
		it('should store session JSON and refresh token in Redis with TTL', async () => {
			await service.createSession({ session: mockSession, refreshToken: 'rt-abc' });

			expect(mockRedisWrite.multi).toHaveBeenCalled();
			expect(mockMulti.set).toHaveBeenCalledWith(
				'session:user-123:session-456',
				JSON.stringify(mockSession),
				'EX',
				30 * 24 * 60 * 60,
			);
			expect(mockMulti.sadd).toHaveBeenCalledWith('sessions:user-123', 'session-456');
			expect(mockMulti.set).toHaveBeenCalledWith(
				'refresh:rt-abc',
				JSON.stringify({ user_id: 'user-123', session_id: 'session-456' }),
				'EX',
				30 * 24 * 60 * 60,
			);
			expect(mockMulti.exec).toHaveBeenCalled();
		});
	});

	describe('getSession', () => {
		it('should retrieve and parse session from Redis read client', async () => {
			mockRedisRead.get.mockResolvedValue(JSON.stringify(mockSession));

			const result = await service.getSession({
				userId: 'user-123',
				sessionId: 'session-456',
			});

			expect(mockRedisRead.get).toHaveBeenCalledWith('session:user-123:session-456');
			expect(result).toEqual(mockSession);
		});

		it('should fall back to write client when read client fails', async () => {
			mockRedisRead.get.mockRejectedValueOnce(new Error('connection error'));
			mockRedisWrite.get.mockResolvedValue(JSON.stringify(mockSession));

			const result = await service.getSession({
				userId: 'user-123',
				sessionId: 'session-456',
			});

			expect(mockRedisWrite.get).toHaveBeenCalledWith('session:user-123:session-456');
			expect(result).toEqual(mockSession);
		});

		it('should return null when session does not exist', async () => {
			mockRedisRead.get.mockResolvedValue(null);

			const result = await service.getSession({
				userId: 'user-123',
				sessionId: 'missing',
			});

			expect(result).toBeNull();
		});
	});

	describe('updateLastActive', () => {
		it('should update last_active field in session', async () => {
			const now = '2026-03-22T12:00:00.000Z';
			jest.spyOn(global.Date.prototype, 'toISOString').mockReturnValue(now);
			mockRedisRead.get.mockResolvedValue(JSON.stringify(mockSession));

			await service.updateLastActive({ userId: 'user-123', sessionId: 'session-456' });

			expect(mockRedisWrite.set).toHaveBeenCalledWith(
				'session:user-123:session-456',
				expect.stringContaining(now),
				'EX',
				30 * 24 * 60 * 60,
			);
		});

		it('should do nothing when session does not exist', async () => {
			mockRedisRead.get.mockResolvedValue(null);

			await service.updateLastActive({ userId: 'user-123', sessionId: 'missing' });

			expect(mockRedisWrite.set).not.toHaveBeenCalled();
		});
	});

	describe('destroySession', () => {
		it('should delete session key and remove from session set', async () => {
			await service.destroySession({ userId: 'user-123', sessionId: 'session-456' });

			expect(mockMulti.del).toHaveBeenCalledWith('session:user-123:session-456');
			expect(mockMulti.srem).toHaveBeenCalledWith('sessions:user-123', 'session-456');
			expect(mockMulti.exec).toHaveBeenCalled();
		});

		it('should also delete refresh token key when provided', async () => {
			await service.destroySession({
				userId: 'user-123',
				sessionId: 'session-456',
				refreshToken: 'rt-abc',
			});

			expect(mockMulti.del).toHaveBeenCalledWith('refresh:rt-abc');
			expect(mockMulti.exec).toHaveBeenCalled();
		});
	});

	describe('destroyAllSessions', () => {
		it('should delete all session keys and the session set', async () => {
			mockRedisRead.smembers.mockResolvedValue(['session-1', 'session-2']);

			await service.destroyAllSessions({ userId: 'user-123' });

			expect(mockMulti.del).toHaveBeenCalledWith('session:user-123:session-1');
			expect(mockMulti.del).toHaveBeenCalledWith('session:user-123:session-2');
			expect(mockMulti.del).toHaveBeenCalledWith('sessions:user-123');
			expect(mockMulti.exec).toHaveBeenCalled();
		});

		it('should fall back to write client when read client fails', async () => {
			mockRedisRead.smembers.mockRejectedValueOnce(new Error('replica error'));
			mockRedisWrite.smembers.mockResolvedValue(['session-1']);

			await service.destroyAllSessions({ userId: 'user-123' });

			expect(mockRedisWrite.smembers).toHaveBeenCalledWith('sessions:user-123');
			expect(mockMulti.del).toHaveBeenCalledWith('session:user-123:session-1');
		});

		it('should do nothing when user has no sessions', async () => {
			mockRedisRead.smembers.mockResolvedValue([]);

			await service.destroyAllSessions({ userId: 'user-123' });

			expect(mockMulti.exec).not.toHaveBeenCalled();
		});
	});

	describe('destroySessionsByCompanyId', () => {
		it('should destroy only sessions matching the given company_id', async () => {
			const sessionWithCompany: ISession = {
				...mockSession,
				session_id: 'session-company',
				company_id: 'company-abc',
			};
			const sessionOther: ISession = {
				...mockSession,
				session_id: 'session-other',
				company_id: 'company-xyz',
			};

			mockRedisRead.smembers.mockResolvedValue(['session-company', 'session-other']);
			mockRedisRead.get
				.mockResolvedValueOnce(JSON.stringify(sessionWithCompany))
				.mockResolvedValueOnce(JSON.stringify(sessionOther));

			await service.destroySessionsByCompanyId({
				userId: 'user-123',
				companyId: 'company-abc',
			});

			expect(mockMulti.del).toHaveBeenCalledWith('session:user-123:session-company');
			expect(mockMulti.del).not.toHaveBeenCalledWith('session:user-123:session-other');
		});
	});

	describe('validateRefreshToken', () => {
		it('should return IRefreshToken when token exists', async () => {
			const payload = { user_id: 'user-123', session_id: 'session-456' };
			mockRedisRead.get.mockResolvedValue(JSON.stringify(payload));

			const result = await service.validateRefreshToken({ refreshToken: 'rt-abc' });

			expect(mockRedisRead.get).toHaveBeenCalledWith('refresh:rt-abc');
			expect(result).toEqual(payload);
		});

		it('should return null when token does not exist', async () => {
			mockRedisRead.get.mockResolvedValue(null);

			const result = await service.validateRefreshToken({ refreshToken: 'invalid' });

			expect(result).toBeNull();
		});

		it('should fall back to write client when read client fails', async () => {
			const payload = { user_id: 'user-123', session_id: 'session-456' };
			mockRedisRead.get.mockRejectedValueOnce(new Error('replica error'));
			mockRedisWrite.get.mockResolvedValue(JSON.stringify(payload));

			const result = await service.validateRefreshToken({ refreshToken: 'rt-abc' });

			expect(mockRedisWrite.get).toHaveBeenCalledWith('refresh:rt-abc');
			expect(result).toEqual(payload);
		});
	});

	describe('rotateRefreshToken', () => {
		it('should store tombstone for old token, create new token, and return new UUID', async () => {
			const result = await service.rotateRefreshToken({
				oldToken: 'old-rt',
				session: mockSession,
			});

			expect(mockMulti.del).toHaveBeenCalledWith('refresh:old-rt');
			expect(mockMulti.set).toHaveBeenCalledWith(
				'refresh_tombstone:old-rt',
				JSON.stringify({ user_id: 'user-123', session_id: 'session-456' }),
				'EX',
				3600,
			);
			expect(mockMulti.set).toHaveBeenCalledWith(
				'refresh:new-token-uuid',
				JSON.stringify({ user_id: 'user-123', session_id: 'session-456' }),
				'EX',
				30 * 24 * 60 * 60,
			);
			expect(result).toBe('new-token-uuid');
		});
	});

	describe('detectRefreshTokenReuse', () => {
		it('should return IRefreshToken when tombstone exists', async () => {
			const payload = { user_id: 'user-123', session_id: 'session-456' };
			mockRedisRead.get.mockResolvedValue(JSON.stringify(payload));

			const result = await service.detectRefreshTokenReuse({ refreshToken: 'stolen-rt' });

			expect(mockRedisRead.get).toHaveBeenCalledWith('refresh_tombstone:stolen-rt');
			expect(result).toEqual(payload);
		});

		it('should return null when no tombstone exists', async () => {
			mockRedisRead.get.mockResolvedValue(null);

			const result = await service.detectRefreshTokenReuse({ refreshToken: 'valid-rt' });

			expect(result).toBeNull();
		});

		it('should fall back to write client when read client fails', async () => {
			const payload = { user_id: 'user-123', session_id: 'session-456' };
			mockRedisRead.get.mockRejectedValueOnce(new Error('replica error'));
			mockRedisWrite.get.mockResolvedValue(JSON.stringify(payload));

			const result = await service.detectRefreshTokenReuse({ refreshToken: 'stolen-rt' });

			expect(mockRedisWrite.get).toHaveBeenCalledWith('refresh_tombstone:stolen-rt');
			expect(result).toEqual(payload);
		});
	});

	describe('updateCompanyContext', () => {
		it('should update company_id and role in session', async () => {
			mockRedisRead.get.mockResolvedValue(JSON.stringify(mockSession));

			await service.updateCompanyContext({
				userId: 'user-123',
				sessionId: 'session-456',
				companyId: 'company-abc',
				role: 'admin',
			});

			const expectedSession = {
				...mockSession,
				company_id: 'company-abc',
				role: 'admin',
			};

			expect(mockRedisWrite.set).toHaveBeenCalledWith(
				'session:user-123:session-456',
				JSON.stringify(expectedSession),
				'EX',
				30 * 24 * 60 * 60,
			);
		});

		it('should do nothing when session does not exist', async () => {
			mockRedisRead.get.mockResolvedValue(null);

			await service.updateCompanyContext({
				userId: 'user-123',
				sessionId: 'missing',
				companyId: 'company-abc',
				role: 'member',
			});

			expect(mockRedisWrite.set).not.toHaveBeenCalled();
		});
	});
});

